{"file_path": "/c/Users/yonim/task79/repo/internal/http/middleware/csrf.go", "content": "package middleware

import (
	"crypto/rand"
	"encoding/hex"
	"net/http"

	"github.com/gin-gonic/gin"
)

const CSRFTokenKey = "csrf_token"

func CSRFMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		// Generate token for GET requests
		if c.Request.Method == http.MethodGet || c.Request.Method == http.MethodHead {
			token := generateCSRFToken()
			c.SetCookie("csrf_token", token, 3600, "/", "", false, false)
			c.Set(CSRFTokenKey, token)
			c.Next()
			return
		}

		// Validate token for mutating requests
		if c.Request.Method == http.MethodPost || c.Request.Method == http.MethodPut || c.Request.Method == http.MethodDelete || c.Request.Method == http.MethodPatch {
			// Skip CSRF for API endpoints that use session auth
			if isAPI(c) {
				c.Next()
				return
			}

			cookieToken, err := c.Cookie("csrf_token")
			if err != nil {
				c.AbortWithStatus(http.StatusForbidden)
				return
			}

			formToken := c.PostForm("csrf_token")
			if formToken == "" {
				formToken = c.GetHeader("X-CSRF-Token")
			}

			if cookieToken == "" || formToken == "" || cookieToken != formToken {
				c.AbortWithStatus(http.StatusForbidden)
				return
			}

			// Rotate token
			newToken := generateCSRFToken()
			c.SetCookie("csrf_token", newToken, 3600, "/", "", false, false)
			c.Set(CSRFTokenKey, newToken)
		}

		c.Next()
	}
}

func generateCSRFToken() string {
	b := make([]byte, 32)
	rand.Read(b)
	return hex.EncodeToString(b)
}

func GetCSRFToken(c *gin.Context) string {
	if v, ok := c.Get(CSRFTokenKey); ok {
		return v.(string)
	}
	return ""
}
"}

