{"file_path": "/c/Users/yonim/task79/repo/internal/http/views/render.go", "content": "package views

import (
	"embed"
	"html/template"
	"io"
	"log/slog"
	"sync"

	"github.com/gin-gonic/gin"
)

//go:embed templates/*.html templates/**/*.html
var TemplatesFS embed.FS

type Renderer struct {
	templates *template.Template
	mu        sync.RWMutex
	isDev     bool
}

func NewRenderer(isDev bool) *Renderer {
	r := &Renderer{isDev: isDev}
	r.loadTemplates()
	return r
}

func (r *Renderer) loadTemplates() {
	funcMap := template.FuncMap{
		"hasPermission": func(perms map[string]bool, perm string) bool {
			return perms != nil && perms[perm]
		},
		"safeHTML": func(s string) template.HTML {
			return template.HTML(s)
		},
		"add": func(a, b int) int {
			return a + b
		},
		"sub": func(a, b int) int {
			return a - b
		},
		"seq": func(n int) []int {
			s := make([]int, n)
			for i := range s {
				s[i] = i + 1
			}
			return s
		},
		"dict": func(values ...interface{}) map[string]interface{} {
			d := make(map[string]interface{})
			for i := 0; i < len(values)-1; i += 2 {
				if key, ok := values[i].(string); ok {
					d[key] = values[i+1]
				}
			}
			return d
		},
	}

	t := template.New("").Funcs(funcMap)
	t, err := t.ParseFS(TemplatesFS, "templates/*.html", "templates/**/*.html")
	if err != nil {
		slog.Error("failed to parse templates", "error", err)
		panic("template parse error: " + err.Error())
	}
	r.templates = t
}

func (r *Renderer) Render(w io.Writer, name string, data interface{}) error {
	if r.isDev {
		r.mu.Lock()
		r.loadTemplates()
		r.mu.Unlock()
	}
	return r.templates.ExecuteTemplate(w, name, data)
}

func (r *Renderer) HTML(c *gin.Context, code int, name string, data interface{}) {
	c.Header("Content-Type", "text/html; charset=utf-8")
	c.Status(code)
	if err := r.Render(c.Writer, name, data); err != nil {
		slog.Error("template render failed", "template", name, "error", err)
	}
}
"}

