<div class="page-header">
    <h1>Metric Definitions</h1>
    {{if hasPermission .Permissions "metric.write"}}
    <button class="btn btn-primary" hx-get="/metrics/new" hx-target="#modal-container">New Metric</button>
    {{end}}
</div>

<div id="metric-list">
    {{if .Metrics}}
    <table class="table">
        <thead>
            <tr><th>Name</th><th>Status</th><th>Version</th><th>Owner</th><th>Dependencies</th><th>Actions</th></tr>
        </thead>
        <tbody>
        {{range .Metrics}}
        <tr>
            <td><a href="/metrics/{{.ID}}">{{.Name}}</a></td>
            <td><span class="badge badge-{{.Status}}">{{.Status}}</span></td>
            <td>v{{.LatestVersion}}</td>
            <td>{{.OwnerName}}</td>
            <td>{{.DependencyCount}}</td>
            <td>
                <a href="/metrics/{{.ID}}" class="btn btn-sm btn-outline">View</a>
                {{if and (hasPermission $.Permissions "metric.activate") (eq .Status "pending_review")}}
                <button class="btn btn-sm btn-primary" hx-post="/api/metrics/{{.ID}}/impact-analysis" hx-target="#modal-container">Impact Analysis</button>
                {{end}}
            </td>
        </tr>
        {{end}}
        </tbody>
    </table>
    {{else}}
    <div class="empty-state"><p>No metrics defined yet.</p></div>
    {{end}}
</div>

<div id="modal-container"></div>
{{end}}
"}

