.top-bar { height: var(--topbar-h); display: flex; align-items: center; justify-content: space-between; padding: 0 1.5rem; background: white; border-bottom: 1px solid var(--gray-200); }
.top-bar-right { display: flex; align-items: center; gap: 1rem; }
.user-info { color: var(--gray-500); font-size: 0.9rem; }

/* Content */
.content { padding: 1.5rem; }

/* Flash */
.flash { padding: 0.75rem 1rem; border-radius: 4px; margin: 0.5rem 1.5rem; display: flex; justify-content: space-between; align-items: center; }
.flash-success { background: #dcfce7; color: #166534; border: 1px solid #86efac; }
.flash-error { background: #fef2f2; color: #991b1b; border: 1px solid #fca5a5; }
.flash-warning { background: #fffbeb; color: #92400e; border: 1px solid #fde68a; }
.flash-close { background: none; border: none; cursor: pointer; font-size: 1.2rem; }

/* Forms */
.form-group { margin-bottom: 1rem; }
.form-group label { display: block; margin-bottom: 0.25rem; font-weight: 500; font-size: 0.9rem; }
.form-control { width: 100%; padding: 0.5rem 0.75rem; border: 1px solid var(--gray-300); border-radius: 4px; font-size: 0.9rem; }
.form-control:focus { outline: none; border-color: var(--primary); box-shadow: 0 0 0 3px rgba(37,99,235,0.1); }
.form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; }
.form-actions { margin-top: 1.5rem; }
.field-error { color: var(--danger); font-size: 0.8rem; display: block; margin-top: 0.25rem; }
.inline-form { display: flex; gap: 0.5rem; align-items: center; flex-wrap: wrap; }

/* Buttons */
.btn { display: inline-flex; align-items: center; padding: 0.5rem 1rem; border: 1px solid transparent; border-radius: 4px; font-size: 0.9rem; cursor: pointer; transition: all .15s; text-decoration: none; }
.btn:hover { text-decoration: none; }
.btn-primary { background: var(--primary); color: white; }
.btn-primary:hover { background: var(--primary-dark); }
.btn-success { background: var(--success); color: white; }
.btn-warning { background: var(--warning); color: white; }
.btn-danger { background: var(--danger); color: white; }
.btn-outline { background: white; border-color: var(--gray-300); color: var(--gray-700); }
.btn-outline:hover { background: var(--gray-100); }
.btn-block { width: 100%; justify-content: center; }
.btn-sm { padding: 0.25rem 0.5rem; font-size: 0.8rem; }
.btn[disabled] { opacity: 0.5; cursor: not-allowed; }

/* Tables */
.table { width: 100%; border-collapse: collapse; background: white; border-radius: 4px; overflow: hidden; }
.table th, .table td { padding: 0.6rem 0.75rem; text-align: left; border-bottom: 1px solid var(--gray-200); font-size: 0.9rem; }
.table th { background: var(--gray-50); font-weight: 600; color: var(--gray-700); }
.table tbody tr:hover { background: var(--gray-50); }
.row-invalid { background: #fef2f2; }

/* Badges */
.badge { display: inline-block; padding: 0.15rem 0.5rem; border-radius: 9999px; font-size: 0.75rem; font-weight: 500; }
.badge-draft { background: var(--gray-200); color: var(--gray-700); }
.badge-published, .badge-active, .badge-valid, .badge-open { background: #dcfce7; color: #166534; }
.badge-unpublished, .badge-deprecated { background: #fef3c7; color: #92400e; }
.badge-created, .badge-pending { background: #dbeafe; color: #1e40af; }
.badge-payment_recorded { background: #d1fae5; color: #065f46; }
.badge-cutoff, .badge-warning { background: #fef3c7; color: #92400e; }
.badge-picking, .badge-processing, .badge-claimed { background: #e0e7ff; color: #3730a3; }
.badge-arrival { background: #fce7f3; color: #9d174d; }
.badge-completed, .badge-fulfilled { background: #dcfce7; color: #166534; }
.badge-cancelled, .badge-failed, .badge-closed { background: #fef2f2; color: #991b1b; }
.badge-abandoned, .badge-out_of_stock, .badge-discontinued { background: #f3f4f6; color: #6b7280; }
.badge-severity-info { background: #e0f2fe; color: #0c4a6e; }
.badge-severity-warning { background: #fef3c7; color: #92400e; }
.badge-severity-critical { background: #fef2f2; color: #991b1b; }
.badge-internal { background: var(--gray-200); color: var(--gray-700); }
.badge-picking { background: #e0e7ff; color: #3730a3; }
.badge-delivery { background: #fce7f3; color: #9d174d; }

/* Cards */
.card { background: white; border: 1px solid var(--gray-200); border-radius: 6px; padding: 1.25rem; margin-bottom: 1rem; }
.card h3 { margin-bottom: 0.75rem; font-size: 1rem; }
.card-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 0.75rem; }
.card-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 1rem; }
.stat-card { text-align: center; padding: 1rem; }
.stat-card h3 { color: var(--gray-500); font-size: 0.85rem; font-weight: normal; }
.stat-value { font-size: 2rem; font-weight: 700; color: var(--primary); }

/* Page */
.page-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 1.5rem; flex-wrap: wrap; gap: 0.5rem; }
.page-header h1 { font-size: 1.5rem; }
.page-actions { display: flex; gap: 0.5rem; }

/* Detail Grid */
.detail-grid { display: grid; grid-template-columns: 1fr 350px; gap: 1rem; }
.detail-list { display: grid; grid-template-columns: 140px 1fr; gap: 0.25rem 1rem; }
.detail-list dt { font-weight: 500; color: var(--gray-500); }

/* Catalog Layout */
.catalog-layout { display: grid; grid-template-columns: 250px 1fr; gap: 1.5rem; }
.filter-sidebar { background: white; border: 1px solid var(--gray-200); border-radius: 6px; padding: 1rem; height: fit-content; }
.filter-sidebar h3 { margin-bottom: 1rem; }

/* Filter Bar */
.filter-bar { margin-bottom: 1rem; }

/* Media */
.media-gallery { display: grid; grid-template-columns: repeat(auto-fill, minmax(150px, 1fr)); gap: 1rem; margin-top: 1rem; }
.media-item { text-align: center; }
.media-thumb { width: 100%; height: 120px; object-fit: cover; border-radius: 4px; }
.media-video-placeholder { width: 100%; height: 120px; background: var(--gray-200); display: flex; align-items: center; justify-content: center; border-radius: 4px; font-size: 0.8rem; }

/* Timeline */
.timeline { position: relative; padding-left: 24px; }
.timeline::before { content: ''; position: absolute; left: 8px; top: 0; bottom: 0; width: 2px; background: var(--gray-200); }
.timeline-item { position: relative; margin-bottom: 1rem; }
.timeline-dot { position: absolute; left: -20px; top: 4px; width: 12px; height: 12px; border-radius: 50%; background: var(--primary); border: 2px solid white; }
.dot-success { background: var(--success); }
.dot-danger { background: var(--danger); }
.timeline-content strong { display: block; }
.timeline-meta { font-size: 0.8rem; color: var(--gray-500); }
.timeline-reason { font-size: 0.85rem; margin-top: 0.25rem; color: var(--gray-700); }

/* Notifications */
.notification-list { display: flex; flex-direction: column; gap: 0.5rem; }
.notification-item { padding: 1rem; border: 1px solid var(--gray-200); border-radius: 4px; cursor: pointer; }
.notification-item.unread { border-left: 3px solid var(--primary); background: #eff6ff; }
.notification-title { font-weight: 600; }
.notification-body { color: var(--gray-500); font-size: 0.9rem; }
.notification-meta { display: flex; gap: 0.5rem; align-items: center; margin-top: 0.5rem; }

/* Announcements */
.announcement-item { padding: 1rem; border: 1px solid var(--gray-200); border-radius: 4px; margin-bottom: 0.5rem; }
.announcement-item.priority-critical { border-left: 3px solid var(--danger); }
.announcement-item.priority-high { border-left: 3px solid var(--warning); }

/* Tabs */
.tabs { display: flex; border-bottom: 2px solid var(--gray-200); margin-bottom: 1rem; }
.tab { padding: 0.5rem 1rem; color: var(--gray-500); border-bottom: 2px solid transparent; margin-bottom: -2px; }
.tab.active { color: var(--primary); border-bottom-color: var(--primary); font-weight: 500; }
.tab:hover { text-decoration: none; color: var(--primary); }

/* Notes */
.note-item { padding: 0.5rem 0; border-bottom: 1px solid var(--gray-100); display: flex; gap: 0.5rem; align-items: baseline; flex-wrap: wrap; }
.note-item small { color: var(--gray-500); }

/* Version Items */
.version-item { padding: 0.5rem 0; border-bottom: 1px solid var(--gray-100); display: flex; gap: 0.5rem; align-items: center; flex-wrap: wrap; }

/* Modal */
.modal-overlay { position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.5); display: flex; align-items: center; justify-content: center; z-index: 1000; }
.modal { background: white; border-radius: 8px; padding: 0; width: 90%; max-width: 500px; max-height: 90vh; overflow-y: auto; }
.modal-lg { max-width: 800px; }
.modal-header { display: flex; justify-content: space-between; align-items: center; padding: 1rem 1.5rem; border-bottom: 1px solid var(--gray-200); }
.modal-close { background: none; border: none; font-size: 1.5rem; cursor: pointer; }
.modal-body { padding: 1.5rem; }

/* Pagination */
.pagination { display: flex; align-items: center; justify-content: center; gap: 1rem; margin-top: 1rem; }
.page-info { color: var(--gray-500); font-size: 0.9rem; }

/* Lineage */
.lineage-list { list-style: none; }
.lineage-list li { padding: 0.25rem 0; }

/* Code */
.code-block { background: var(--gray-100); padding: 0.5rem; border-radius: 4px; font-size: 0.85rem; overflow-x: auto; }
.small-json { font-size: 0.75rem; word-break: break-all; }

/* Empty State */
.empty-state { text-align: center; padding: 2rem; color: var(--gray-500); }

/* Action Buttons */
.action-buttons { display: flex; gap: 0.5rem; flex-wrap: wrap; }

/* Impact */
.impact-summary p { margin-bottom: 0.25rem; }

/* Responsive */
@media (max-width: 1024px) {
    .detail-grid { grid-template-columns: 1fr; }
    .catalog-layout { grid-template-columns: 1fr; }
}
@media (max-width: 768px) {
    .sidebar { display: none; }
    .main-area { margin-left: 0; }
    .form-row { grid-template-columns: 1fr; }
}
"}

