{"file_path": "/c/Users/yonim/task79/repo/internal/orders/service.go", "content": "package orders

import (
	"context"
	"fmt"

	"fleetcommerce/internal/audit"

	"github.com/jackc/pgx/v5/pgxpool"
)

type Service struct {
	repo     *Repository
	pool     *pgxpool.Pool
	auditSvc *audit.Service
}

func NewService(repo *Repository, pool *pgxpool.Pool, auditSvc *audit.Service) *Service {
	return &Service{repo: repo, pool: pool, auditSvc: auditSvc}
}

func (s *Service) ListOrders(ctx context.Context, p ListParams) ([]Order, int, error) {
	return s.repo.ListOrders(ctx, p)
}

func (s *Service) GetOrder(ctx context.Context, id int) (*Order, error) {
	return s.repo.GetOrder(ctx, id)
}

func (s *Service) CreateOrder(ctx context.Context, p CreateOrderParams) (int, string, error) {
	tx, err := s.pool.Begin(ctx)
	if err != nil {
		return 0, "", err
	}
	defer tx.Rollback(ctx)

	id, orderNumber, err := s.repo.CreateOrder(ctx, tx, p)
	if err != nil {
		return 0, "", fmt.Errorf("create order: %w", err)
	}

	for _, line := range p.Lines {
		if err := s.repo.CreateOrderLine(ctx, tx, id, line); err != nil {
			return 0, "", fmt.Errorf("create order line: %w", err)
		}
	}

	// Record initial state
	s.repo.CreateStateHistory(ctx, tx, id, "", StatusCreated, &p.CreatedBy, "user", "Order created from cart")

	s.auditSvc.LogTx(ctx, tx, audit.LogParams{
		EntityType:  "order",
		EntityID:    id,
		Action:      "created",
		ActorUserID: &p.CreatedBy,
		After:       map[string]interface{}{"order_number": orderNumber, "source_cart_id": p.SourceCartID},
	})

	if err := tx.Commit(ctx); err != nil {
		return 0, "", err
	}
	return id, orderNumber, nil
}

func (s *Service) TransitionOrder(ctx context.Context, orderID int, toStatus string, actorID *int, actorType, reason string) error {
	order, err := s.repo.GetOrder(ctx, orderID)
	if err != nil {
		return err
	}

	if err := ValidateTransition(order.Status, toStatus); err != nil {
		return err
	}

	tx, err := s.pool.Begin(ctx)
	if err != nil {
		return err
	}
	defer tx.Rollback(ctx)

	if err := s.repo.SetOrderStatus(ctx, tx, orderID, toStatus); err != nil {
		return err
	}

	s.repo.CreateStateHistory(ctx, tx, orderID, order.Status, toStatus, actorID, actorType, reason)

	s.auditSvc.LogTx(ctx, tx, audit.LogParams{
		EntityType:  "order",
		EntityID:    orderID,
		Action:      "transitioned",
		ActorUserID: actorID,
		Before:      map[string]string{"status": order.Status},
		After:       map[string]string{"status": toStatus},
		Metadata:    map[string]string{"reason": reason},
	})

	return tx.Commit(ctx)
}

func (s *Service) RecordPayment(ctx context.Context, orderID int, actorID int) error {
	order, err := s.repo.GetOrder(ctx, orderID)
	if err != nil {
		return err
	}

	if err := ValidateTransition(order.Status, StatusPaymentRecorded); err != nil {
		return err
	}

	tx, err := s.pool.Begin(ctx)
	if err != nil {
		return err
	}
	defer tx.Rollback(ctx)

	s.repo.SetPaymentRecorded(ctx, tx, orderID)
	s.repo.CreatePaymentRecord(ctx, tx, orderID, actorID)
	s.repo.CreateStateHistory(ctx, tx, orderID, order.Status, StatusPaymentRecorded, &actorID, "user", "Payment recorded")

	s.auditSvc.LogTx(ctx, tx, audit.LogParams{
		EntityType:  "order",
		EntityID:    orderID,
		Action:      "payment_recorded",
		ActorUserID: &actorID,
	})

	return tx.Commit(ctx)
}

func (s *Service) AddNote(ctx context.Context, orderID int, noteType, content string, authorID int) (int, error) {
	return s.repo.CreateNote(ctx, orderID, noteType, content, authorID)
}

func (s *Service) ListOrderLines(ctx context.Context, orderID int) ([]OrderLine, error) {
	return s.repo.ListOrderLines(ctx, orderID)
}

func (s *Service) ListNotes(ctx context.Context, orderID int) ([]OrderNote, error) {
	return s.repo.ListNotes(ctx, orderID)
}

func (s *Service) ListHistory(ctx context.Context, orderID int) ([]OrderStateHistory, error) {
	return s.repo.ListHistory(ctx, orderID)
}

func (s *Service) GetAllowedTransitions(status string) []string {
	return GetAllowedTransitions(status)
}

// ProcessCutoffs transitions orders past cutoff time
func (s *Service) ProcessCutoffs(ctx context.Context, cutoffMinutes int) (int, error) {
	orders, err := s.repo.FindCreatedOrdersForCutoff(ctx, cutoffMinutes)
	if err != nil {
		return 0, err
	}

	count := 0
	for _, order := range orders {
		tx, err := s.pool.Begin(ctx)
		if err != nil {
			continue
		}

		s.repo.SetCutoff(ctx, tx, order.ID)
		s.repo.CreateStateHistory(ctx, tx, order.ID, StatusCreated, StatusCutoff, nil, "system", "Automatic cutoff - payment not recorded within 30 minutes")

		s.auditSvc.LogTx(ctx, tx, audit.LogParams{
			EntityType: "order",
			EntityID:   order.ID,
			Action:     "auto_cutoff",
			Metadata:   map[string]string{"reason": "Payment not recorded within cutoff window"},
		})

		if err := tx.Commit(ctx); err == nil {
			count++
		} else {
			tx.Rollback(ctx)
		}
	}
	return count, nil
}

func (s *Service) SplitOrder(ctx context.Context, orderID int, actorID int, backorderLineIDs []int) (int, error) {
	order, err := s.repo.GetOrder(ctx, orderID)
	if err != nil {
		return 0, err
	}

	tx, err := s.pool.Begin(ctx)
	if err != nil {
		return 0, err
	}
	defer tx.Rollback(ctx)

	// Create child order for backordered items
	childID, childNumber, err := s.repo.CreateOrder(ctx, tx, CreateOrderParams{
		CustomerAccountID: *order.CustomerAccountID,
		SourceCartID:      *order.SourceCartID,
		Location:          order.Location,
		CreatedBy:         actorID,
	})
	if err != nil {
		return 0, err
	}

	// Set parent link
	tx.Exec(ctx, `UPDATE orders SET split_parent_order_id = $1 WHERE id = $2`, orderID, childID)

	// Move backordered lines to child
	for _, lineID := range backorderLineIDs {
		tx.Exec(ctx, `UPDATE order_lines SET order_id = $1 WHERE id = $2`, childID, lineID)
	}

	// Update parent status
	s.repo.SetOrderStatus(ctx, tx, orderID, StatusSplit)
	s.repo.CreateStateHistory(ctx, tx, orderID, order.Status, StatusSplit, &actorID, "user", fmt.Sprintf("Order split, child order: %s", childNumber))

	s.auditSvc.LogTx(ctx, tx, audit.LogParams{
		EntityType:  "order",
		EntityID:    orderID,
		Action:      "split",
		ActorUserID: &actorID,
		Metadata:    map[string]interface{}{"child_order_id": childID, "child_order_number": childNumber},
	})

	if err := tx.Commit(ctx); err != nil {
		return 0, err
	}
	return childID, nil
}

func (s *Service) CountActive(ctx context.Context) (int, error) {
	return s.repo.CountActive(ctx)
}

func (s *Service) Repo() *Repository {
	return s.repo
}
"}

