		json.Unmarshal(rawData, &data)

		// Find or create brand
		var brandID int
		err := s.pool.QueryRow(ctx, `SELECT id FROM brands WHERE name=$1`, data["brand"]).Scan(&brandID)
		if err != nil {
			s.pool.QueryRow(ctx, `INSERT INTO brands (name) VALUES ($1) RETURNING id`, data["brand"]).Scan(&brandID)
		}

		// Find or create series
		var seriesID int
		err = s.pool.QueryRow(ctx, `SELECT id FROM series WHERE brand_id=$1 AND name=$2`, brandID, data["series"]).Scan(&seriesID)
		if err != nil {
			s.pool.QueryRow(ctx, `INSERT INTO series (brand_id, name) VALUES ($1, $2) RETURNING id`, brandID, data["series"]).Scan(&seriesID)
		}

		year, _ := strconv.Atoi(data["year"])
		stock := 0
		if s, err := strconv.Atoi(data["stock_quantity"]); err == nil {
			stock = s
		}
		pubStatus := "draft"
		if ps := data["publication_status"]; ps != "" {
			pubStatus = ps
		}

		_, err = s.pool.Exec(ctx, `INSERT INTO vehicle_models (brand_id, series_id, model_code, model_name, year, description, publication_status, stock_quantity, expiry_date)
			VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9)`,
			brandID, seriesID, data["model_code"], data["model_name"], year, data["description"], pubStatus, stock, nilIfEmpty(data["expiry_date"]))

		if err == nil {
			s.pool.Exec(ctx, `UPDATE csv_import_rows SET status='committed' WHERE id=$1`, rowID)
			committed++
		}
	}

	s.pool.Exec(ctx, `UPDATE csv_import_jobs SET status='committed', committed_rows=$1, completed_at=NOW() WHERE id=$2`, committed, jobID)

	s.auditSvc.Log(ctx, audit.LogParams{
		EntityType:  "csv_import",
		EntityID:    jobID,
		Action:      "committed",
		ActorUserID: &actorID,
		Metadata:    map[string]int{"committed_rows": committed},
	})

	return nil
}

func nilIfEmpty(s string) interface{} {
	if s == "" {
		return nil
	}
	return s
}
"}

