	for _, m := range models {
		c.Writer.WriteString(fmt.Sprintf("%s,%s,%s,%s,%d,%s,%s,%d,%s\n",
			m.ModelCode, m.ModelName, m.BrandName, m.SeriesName, m.Year, m.Description, m.PublicationStatus, m.StockQuantity, m.ExpiryDate))
