{"file_path": "/c/Users/yonim/task79/repo/internal/alerts/service_test.go", "content": "package alerts

import "testing"

func TestAlertLifecycleValidation(t *testing.T) {
	// Test that resolution notes are required for close
	if err := (Service{}).validateCloseNotes(""); err == nil {
		t.Error("expected error when closing alert without resolution notes")
	}
	if err := (Service{}).validateCloseNotes("Fixed the issue by restocking"); err != nil {
		t.Errorf("unexpected error: %v", err)
	}
}

func (s Service) validateCloseNotes(notes string) error {
	if notes == "" {
		return ErrResolutionRequired
	}
	return nil
}

func TestAlertStatusTransitions(t *testing.T) {
	// open -> claimed: valid
	// open -> processing: invalid (must claim first)
	// claimed -> processing: valid
	// processing -> closed: valid (with notes)
	// closed -> open: invalid

	validTransitions := map[string][]string{
		"open":       {"claimed"},
		"claimed":    {"processing"},
		"processing": {"closed"},
	}

	for from, tos := range validTransitions {
		for _, to := range tos {
			if !isValidAlertTransition(from, to) {
				t.Errorf("expected valid transition from %q to %q", from, to)
			}
		}
	}

	invalidTransitions := [][2]string{
		{"open", "processing"},
		{"open", "closed"},
		{"claimed", "closed"},
		{"closed", "open"},
		{"processing", "open"},
	}

	for _, tt := range invalidTransitions {
		if isValidAlertTransition(tt[0], tt[1]) {
