func TestAlertStatusTransitions(t *testing.T) {
	// open -> claimed: valid
	// open -> processing: invalid (must claim first)
	// claimed -> processing: valid
	// processing -> closed: valid (with notes)
	// closed -> open: invalid

	validTransitions := map[string][]string{
		"open":       {"claimed"},
		"claimed":    {"processing"},
		"processing": {"closed"},
