1	package middleware
2	
3	import (
4		"crypto/rand"
5		"encoding/hex"
6		"net/http"
7	
8		"github.com/gin-gonic/gin"
9	)
10	
11	const CSRFTokenKey = "csrf_token"
12	
13	func CSRFMiddleware() gin.HandlerFunc {
14		return func(c *gin.Context) {
15			// Generate token for GET requests
16			if c.Request.Method == http.MethodGet || c.Request.Method == http.MethodHead {
17				token := generateCSRFToken()
18				c.SetCookie("csrf_token", token, 3600, "/", "", false, false)
19				c.Set(CSRFTokenKey, token)
20				c.Next()
21				return
22			}
23	
24			// Validate token for mutating requests
25			if c.Request.Method == http.MethodPost || c.Request.Method == http.MethodPut || c.Request.Method == http.MethodDelete || c.Request.Method == http.MethodPatch {
26				// Skip CSRF for API endpoints that use session auth
27				if isAPI(c) {
28					c.Next()
29					return
30				}
31	
32				cookieToken, err := c.Cookie("csrf_token")
33				if err != nil {
34					c.AbortWithStatus(http.StatusForbidden)
35					return
36				}
37	
38				formToken := c.PostForm("csrf_token")
39				if formToken == "" {
40					formToken = c.GetHeader("X-CSRF-Token")
41				}
42	
43				if cookieToken == "" || formToken == "" || cookieToken != formToken {
44					c.AbortWithStatus(http.StatusForbidden)
45					return
46				}
47	
48				// Rotate token
49				newToken := generateCSRFToken()
50				c.SetCookie("csrf_token", newToken, 3600, "/", "", false, false)
51				c.Set(CSRFTokenKey, newToken)
52			}
53	
54			c.Next()
55		}
56	}
57	
58	func generateCSRFToken() string {
59		b := make([]byte, 32)
60		rand.Read(b)
61		return hex.EncodeToString(b)
62	}
63	
64	func GetCSRFToken(c *gin.Context) string {
65		if v, ok := c.Get(CSRFTokenKey); ok {
66			return v.(string)
67		}
68		return ""
69	}
