import (
	"crypto/rand"
	"encoding/hex"
	"net/http"

	"github.com/gin-gonic/gin"
)

const CSRFTokenKey = "csrf_token"

func CSRFMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		// Generate token for GET/HEAD requests
		if c.Request.Method == http.MethodGet || c.Request.Method == http.MethodHead {
			token := generateCSRFToken()
			c.SetCookie("csrf_token", token, 3600, "/", "", false, false)
			c.Set(CSRFTokenKey, token)
			c.Next()
			return
		}

		// Validate token for all mutating requests (POST/PUT/DELETE/PATCH)
		// including API routes — they use cookie-based session auth and need CSRF protection.
		if c.Request.Method == http.MethodPost || c.Request.Method == http.MethodPut ||
			c.Request.Method == http.MethodDelete || c.Request.Method == http.MethodPatch {

			cookieToken, err := c.Cookie("csrf_token")
			if err != nil || cookieToken == "" {
				c.AbortWithStatus(http.StatusForbidden)
				return
			}

			// Accept token from form field, header (for HTMX/JS), or query param
			formToken := c.PostForm("csrf_token")
			if formToken == "" {
				formToken = c.GetHeader("X-CSRF-Token")
			}

			if formToken == "" || cookieToken != formToken {
				c.JSON(http.StatusForbidden, gin.H{"ok": false, "message": "CSRF token missing or invalid"})
				c.Abort()
				return
			}

			// Rotate token after successful validation
			newToken := generateCSRFToken()
			c.SetCookie("csrf_token", newToken, 3600, "/", "", false, false)
			c.Set(CSRFTokenKey, newToken)
		}

		c.Next()
	}
}

func generateCSRFToken() string {
	b := make([]byte, 32)
	rand.Read(b)
	return hex.EncodeToString(b)
}

func GetCSRFToken(c *gin.Context) string {
	if v, ok := c.Get(CSRFTokenKey); ok {
		return v.(string)
	}
	return ""
}
"}

