}", "new_string": "func (s *Service) CreateOrder(ctx context.Context, p CreateOrderParams) (int, string, error) {
	tx, err := s.pool.Begin(ctx)
	if err != nil {
		return 0, "", err
	}
	defer tx.Rollback(ctx)

	id, orderNumber, err := s.repo.CreateOrder(ctx, tx, p)
	if err != nil {
		return 0, "", fmt.Errorf("create order: %w", err)
	}

	hasBackorder := false
	for _, line := range p.Lines {
		// Query current stock for allocation
		var currentStock int
		err := tx.QueryRow(ctx, `SELECT stock_quantity FROM vehicle_models WHERE id = $1 FOR UPDATE`, line.VehicleModelID).Scan(&currentStock)
		if err != nil {
			currentStock = 0
		}

		allocated := line.QuantityRequested
		backordered := 0
		lineStatus := "allocated"

		if currentStock < line.QuantityRequested {
			allocated = currentStock
			if allocated < 0 {
				allocated = 0
			}
			backordered = line.QuantityRequested - allocated
			if allocated == 0 {
				lineStatus = "backordered"
			} else {
				lineStatus = "partial"
			}
			hasBackorder = true
		}

		// Deduct allocated stock
		if allocated > 0 {
			tx.Exec(ctx, `UPDATE vehicle_models SET stock_quantity = stock_quantity - $1, updated_at = NOW() WHERE id = $2`, allocated, line.VehicleModelID)
		}

		line.StockSnapshot = currentStock
		if err := s.repo.CreateOrderLineWithAllocation(ctx, tx, id, line, allocated, backordered, lineStatus); err != nil {
			return 0, "", fmt.Errorf("create order line: %w", err)
		}
	}

	// Record initial state
	s.repo.CreateStateHistory(ctx, tx, id, "", StatusCreated, &p.CreatedBy, "user", "Order created from cart")

	s.auditSvc.LogTx(ctx, tx, audit.LogParams{
		EntityType:  "order",
		EntityID:    id,
		Action:      "created",
		ActorUserID: &p.CreatedBy,
		After: map[string]interface{}{
			"order_number":   orderNumber,
			"source_cart_id": p.SourceCartID,
			"has_backorder":  hasBackorder,
			"line_count":     len(p.Lines),
		},
	})

	// If any lines are backordered, mark the order accordingly
	if hasBackorder {
		s.repo.SetOrderStatus(ctx, tx, id, StatusPartiallyBackordered)
		s.repo.CreateStateHistory(ctx, tx, id, StatusCreated, StatusPartiallyBackordered, &p.CreatedBy, "system", "Order contains backordered lines due to insufficient stock")
	}

	if err := tx.Commit(ctx); err != nil {
		return 0, "", err
	}
	return id, orderNumber, nil
}"}

