{"file_path": "/c/Users/yonim/task79/repo/internal/orders/service_test.go", "content": "package orders

import (
	"context"
	"strings"
	"testing"
)

// TestTransitionOrderBlocksPaymentRecorded verifies that the generic
// TransitionOrder path refuses to transition to payment_recorded.
// This is the critical payment governance fix — payment must go through
// the dedicated RecordPayment endpoint which has PermOrderPayment.
func TestTransitionOrderBlocksPaymentRecorded(t *testing.T) {
	// Service with nil pool — we only need to test the guard before DB access
	svc := &Service{}
	err := svc.TransitionOrder(context.Background(), 1, StatusPaymentRecorded, nil, "user", "")
	if err == nil {
		t.Fatal("expected error when transitioning to payment_recorded via generic path")
	}
	if !strings.Contains(err.Error(), "dedicated payment-recorded endpoint") {
		t.Errorf("error should mention dedicated endpoint, got: %v", err)
	}
}

// TestTransitionOrderAllowsOtherStates verifies the guard doesn't block
// legitimate transitions. This will fail with nil pool (can't reach DB),
// but proves the guard specifically targets only payment_recorded.
func TestTransitionOrderDoesNotBlockOtherStates(t *testing.T) {
	svc := &Service{}
	// These will fail at DB access (nil pool), but should NOT fail at the guard
	err := svc.TransitionOrder(context.Background(), 1, StatusCutoff, nil, "system", "")
	if err != nil && strings.Contains(err.Error(), "dedicated payment-recorded endpoint") {
		t.Error("cutoff should not be blocked by payment guard")
	}
	err = svc.TransitionOrder(context.Background(), 1, StatusCancelled, nil, "user", "")
	if err != nil && strings.Contains(err.Error(), "dedicated payment-recorded endpoint") {
		t.Error("cancelled should not be blocked by payment guard")
	}
	err = svc.TransitionOrder(context.Background(), 1, StatusPicking, nil, "user", "")
	if err != nil && strings.Contains(err.Error(), "dedicated payment-recorded endpoint") {
		t.Error("picking should not be blocked by payment guard")
	}
}
"}

