{"file_path": "/c/Users/yonim/task79/repo/internal/http/views/templ/notifications.templ", "content": "package templ

import "fmt"

templ NotificationsPage(data PageData, activeTab string, notifications []NotificationView, announcements []AnnouncementView, preferences []PreferenceView, prefTypes []string, exportQueue []ExportQueueView) {
	@Layout(data) {
		<div class="page-header">
			<h1>Notification Center</h1>
			<form method="POST" action="/api/notifications/bulk-read" style="display:inline">
				<input type="hidden" name="csrf_token" value={ data.CSRFToken }/>
				<button type="submit" class="btn btn-outline">Mark All Read</button>
			</form>
		</div>
		<div class="tabs">
			<a href="/notifications" class={ tabClass(activeTab, "inbox") }>Inbox</a>
			<a href="/notifications?tab=announcements" class={ tabClass(activeTab, "announcements") }>Announcements</a>
			<a href="/notifications?tab=preferences" class={ tabClass(activeTab, "preferences") }>Preferences</a>
			<a href="/notifications?tab=export-queue" class={ tabClass(activeTab, "export-queue") }>Export Queue</a>
		</div>
		<div class="tab-content">
			if activeTab == "inbox" || activeTab == "" {
				@notifInboxTab(notifications)
			}
			if activeTab == "announcements" {
				@notifAnnouncementsTab(announcements)
			}
			if activeTab == "preferences" {
				@notifPreferencesTab(data, preferences, prefTypes)
			}
			if activeTab == "export-queue" {
				@notifExportQueueTab(exportQueue)
			}
		</div>
	}
}

templ notifInboxTab(notifications []NotificationView) {
	<div class="notification-list">
		for _, n := range notifications {
			<div class={ notifClass(n.IsRead) } hx-post={ fmt.Sprintf("/api/notifications/%d/read", n.ID) } hx-trigger="click" hx-swap="none">
				<div class="notification-title">{ n.Title }</div>
				<div class="notification-body">{ n.Body }</div>
				<div class="notification-meta">
					<span class="badge">{ n.Type }</span>
					<small>{ n.CreatedAt }</small>
				</div>
			</div>
		}
		if len(notifications) == 0 {
			<div class="empty-state"><p>No notifications.</p></div>
		}
	</div>
}

templ notifAnnouncementsTab(announcements []AnnouncementView) {
	for _, a := range announcements {
		<div class={ "announcement-item priority-" + a.Priority }>
			<h3>{ a.Title }</h3>
			<p>{ a.Body }</p>
			<small>{ a.CreatedAt } | Priority: { a.Priority }</small>
		</div>
	}
	if len(announcements) == 0 {
		<div class="empty-state"><p>No active announcements.</p></div>
	}
}

templ notifPreferencesTab(data PageData, preferences []PreferenceView, prefTypes []string) {
	<form method="POST" action="/api/notification-preferences" hx-post="/api/notification-preferences" hx-swap="none">
		<input type="hidden" name="csrf_token" value={ data.CSRFToken }/>
		<table class="table">
			<thead><tr><th>Event Type</th><th>In-App</th><th>Email</th><th>SMS</th><th>Webhook</th></tr></thead>
			<tbody>
				for _, et := range prefTypes {
					<tr>
						<td>{ et }</td>
						<td><input type="checkbox" name={ "in_app_" + et } checked?={ hasPref(preferences, "in_app", et) }/></td>
						<td><input type="checkbox" name={ "email_" + et } checked?={ hasPref(preferences, "email", et) }/></td>
						<td><input type="checkbox" name={ "sms_" + et } checked?={ hasPref(preferences, "sms", et) }/></td>
						<td><input type="checkbox" name={ "webhook_" + et } checked?={ hasPref(preferences, "webhook", et) }/></td>
					</tr>
				}
			</tbody>
		</table>
		<button type="submit" class="btn btn-primary">Save Preferences</button>
	</form>
}

templ notifExportQueueTab(exportQueue []ExportQueueView) {
	if len(exportQueue) > 0 {
		<table class="table">
			<thead><tr><th>ID</th><th>Channel</th><th>Recipient</th><th>Status</th><th>Attempts</th><th>Created</th></tr></thead>
			<tbody>
				for _, eq := range exportQueue {
					<tr>
						<td>{ fmt.Sprintf("#%d", eq.ID) }</td>
						<td>{ eq.Channel }</td>
						<td>{ eq.Recipient }</td>
						<td><span class={ "badge badge-" + eq.Status }>{ eq.Status }</span></td>
						<td>{ fmt.Sprintf("%d/%d", eq.Attempts, eq.MaxAttempts) }</td>
						<td>{ eq.CreatedAt }</td>
					</tr>
				}
			</tbody>
		</table>
	} else {
		<div class="empty-state"><p>No export queue items.</p></div>
	}
}

templ AlertsPage(data PageData, alertList []AlertView, filterStatus string) {
	@Layout(data) {
		<div class="page-header">
			<h1>Alerts</h1>
			if data.Permissions["alert.manage"] {
				<button class="btn btn-outline" hx-post="/api/alerts/evaluate" hx-swap="none">Evaluate Now</button>
			}
		</div>
		if len(alertList) > 0 {
			<table class="table">
				<thead><tr><th>ID</th><th>Title</th><th>Severity</th><th>Entity</th><th>Status</th><th>Claimed By</th><th>Actions</th></tr></thead>
				<tbody>
					for _, a := range alertList {
						<tr>
